import React, { useState, useEffect } from 'react'; 
import { Box, FormControl, FormLabel, Input, Button, Heading, useToast } from '@chakra-ui/react';
import { intervalToDuration } from 'date-fns';
import ReactSelect from 'react-select';
import axios from 'axios';

const QueueTaskTracker = () => {
  const [selectedQueue, setSelectedQueue] = useState(null);
  const [taskId, setTaskId] = useState('');
  const [taskLog, setTaskLog] = useState([]);
  const [startTime, setStartTime] = useState(null);
  const [timeElapsed, setTimeElapsed] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const [timeBeforePause, setTimeBeforePause] = useState(0);
  const toast = useToast();

  const queues = [
    'FH Discount Dispute', 
    'MP Discount Dispute', 
    'FH Pre-service Dispute',
    'MP Pre-service Dispute',
  ]; 

  useEffect(() => {
    let timer;
    if (!isPaused && startTime) {
      timer = setInterval(() => {
        setTimeElapsed(((Date.now() - startTime) / 1000).toFixed(0));
      }, 1000);
    } else {
      clearInterval(timer);
    }
    return () => clearInterval(timer);
  }, [isPaused, startTime]);

  const handleQueueChange = (event) => {
    if (event) {
      setSelectedQueue(event);
      setStartTime(Date.now());
      setIsPaused(false);
      setTimeElapsed(0);
    }
  };

  const handleTaskComplete = async () => {
    if (taskId.trim() && selectedQueue) {
      const endTime = Date.now();
      const timeSpent = startTime ? ((endTime - startTime) / 1000).toFixed(2) : 'N/A';

      const newTask = {
        taskId,
        timeSpent,
        queue: selectedQueue.value,
        comment: '',
      };

      console.log('Adding new task to taskLog:', newTask);
      setTaskLog((prevLog) => [...prevLog, newTask]);
      console.log('Updated taskLog:', [...taskLog, newTask]);

      try {
        console.log("Attempting to save task:", newTask);

        const response = await axios.post('http://localhost:5000/api/tasks', newTask, {
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`, // Make sure token is correct
          }
        });

        if (response.status !== 201) {
          const errorDetails = response.data;
          console.error('Server responded with an error:', response.status, response.statusText, errorDetails);
          throw new Error(`Failed to save task to the server. Status: ${response.status}, Details: ${errorDetails?.message || 'No details provided'}`);
        }

        const savedTask = response.data;
        setTaskLog((prevLog) =>
          prevLog.map((task, index) =>
            index === prevLog.length - 1 ? savedTask : task
          )
        );

        console.log('Task saved successfully:', savedTask);
      } catch (error) {
        console.error('Error saving task:', error);
        toast({
          title: 'Error saving task',
          description: error.message,
          status: 'error',
          duration: 3000,
          isClosable: true,
        });
      }

      setTaskId('');
      setStartTime(Date.now());
    }
  };

  const handlePauseResume = () => {
    if (isPaused) {
      setStartTime(Date.now() - timeBeforePause);
      setIsPaused(false);
    } else {
      setTimeBeforePause(Date.now() - startTime);
      setIsPaused(true);
    }
  };

  const handleCommentChange = (i, v) => {
    setTaskLog((prevTaskLog) => {
      const updatedTaskLog = [...prevTaskLog];
      updatedTaskLog[i].comment = v;
      return updatedTaskLog;
    });
  };

  const formatTime = (seconds) => {
    if (seconds === 0 || seconds === 'N/A') return '0s';
    const duration = intervalToDuration({
      start: 0,
      end: seconds * 1000,
    });

    const hours = duration.hours;
    const minutes = duration.minutes;
    const secs = duration.seconds;

    return `${hours > 0 ? `${hours}h ` : ''}${minutes > 0 ? `${minutes}m ` : ''}${secs}s`;
  };

  // Handle End of Today button click
  const handleEndOfDay = async () => {
    try {
      // Loop through all tasks in the log and ensure they're saved
      for (const task of taskLog) {
        if (task._id) {
          // Update existing task
          await axios.put(`http://localhost:5000/api/tasks/${task._id}`, task, {
            headers: {
              'Authorization': `Bearer ${localStorage.getItem('authToken')}`
            }
          });
        } else {
          // Save new task
          await axios.post('http://localhost:5000/api/tasks', task, {
            headers: {
              'Authorization': `Bearer ${localStorage.getItem('authToken')}`
            }
          });
        }
      }

      console.log('All tasks successfully logged to the database');

      // Stop the timer
      setIsPaused(true);
      setTimeBeforePause(0);
      setTimeElapsed(0);
      setStartTime(null);
    } catch (error) {
      console.error('Error logging tasks at end of day:', error);
      toast({
        title: 'Error saving end of day tasks',
        description: error.message,
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    }
  };

  return (
    <Box maxW="2/3" w="66vw" mx="auto" mt={10} p={5} borderWidth={1} borderRadius="lg">
      <Heading as="h3" size="lg" mb={4}>
        Task Tracker
      </Heading>

      {/* Queue Selection */}
      <FormControl id="queue-selection" mb={4}>
        <FormLabel>Select Queue</FormLabel>
        <ReactSelect
          placeholder="Type Your Queue Name"
          value={selectedQueue}
          onChange={handleQueueChange}
          options={queues.map((queue) => ({ value: queue, label: queue }))}
          isSearchable
        />
      </FormControl>

      {/* Task Input */}
      {selectedQueue && (
        <>
          <FormControl id="task-id" mb={4}>
            <FormLabel>Enter Task ID</FormLabel>
            <Input
              type="number"
              value={taskId}
              onChange={(e) => setTaskId(e.target.value)}
              placeholder="Enter Task ID"
            />
          </FormControl>

          {/* Real-Time Timer Display */}
          {startTime && (
            <Box mt={4} my={6} fontWeight="bold">
              Time Spent on Current Task: {formatTime(timeElapsed)}
            </Box>
          )}

          <Button colorScheme="teal" mr={4} onClick={handleTaskComplete}>
            Finish Task
          </Button>
          <Button colorScheme="teal" onClick={handlePauseResume}>
            {isPaused ? 'Resume Timer' : 'Pause Timer'}
          </Button>
        </>
      )}

      {/* Task Log */}
      <Box my={6}>
        <Heading as="h4" size="md" mb={4}>
          Task Log
        </Heading>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ whiteSpace: 'nowrap', border: '1px solid #ccc', padding: '8px', width: '15%' }}>Task ID</th>
              <th style={{ whiteSpace: 'nowrap', border: '1px solid #ccc', padding: '8px', width: '15%' }}>Queue</th>
              <th style={{ whiteSpace: 'nowrap', border: '1px solid #ccc', padding: '8px', width: '15%' }}>Time Spent</th>
              <th style={{ whiteSpace: 'nowrap', border: '1px solid #ccc', padding: '8px', width: '55%' }}>Notes</th>
            </tr>
          </thead>
          <tbody>
            {taskLog.map((task, index) => (
              <tr key={index}>
                <td style={{ whiteSpace: 'nowrap', border: '1px solid #ccc', padding: '8px', width: '15%' }}>
                  {task?.taskId || 'N/A'}
                </td>
                <td style={{ whiteSpace: 'nowrap', border: '1px solid #ccc', padding: '8px', width: '15%' }}>
                  {task?.queue || 'N/A'}
                </td>
                <td style={{ whiteSpace: 'nowrap', border: '1px solid #ccc', padding: '8px', width: '15%' }}>
                  {formatTime(task?.timeSpent) || 'N/A'}
                </td>
                <td style={{ whiteSpace: 'nowrap', border: '1px solid #ccc', padding: '8px', width: '55%' }}>
                  <Input
                    type="text"
                    placeholder="Add a comment"
                    value={task?.comment || ''}
                    onChange={(e) => handleCommentChange(index, e.target.value)}
                  />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </Box>

      {/* End of Today Button */}
      <Button colorScheme="blue" onClick={handleEndOfDay}>
        End of Today
      </Button>
    </Box>
  );
};

export default QueueTaskTracker;
